import os
import pymysql
import json

def search_data(request):
    """
    Cloud Function that queries a Cloud SQL MySQL database.
    It builds dynamic SQL queries from HTTP request parameters
    for flexible searching using string concatenation.
    """
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    db_table = os.environ.get('DB_TABLE', 'your_default_table') # Set your default table name

    if not all([db_host, db_user, db_password, db_name]):
        return json.dumps({'error': 'Missing database connection environment variables'}), 500, {'Content-Type': 'application/json'}

    conn = None
    cursor = None
    try:
        # Establish database connection
        conn = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor # Returns results as dictionaries
        )
        cursor = conn.cursor()

        # Start building the base SQL query
        sql_query = f"SELECT * FROM {db_table}"

        # Collect filter conditions from HTTP request parameters
        filters = []
        for key, value in request.args.items():
            # IMPORTANT: Using string concatenation for SQL queries, especially with user input,
            # is highly susceptible to SQL Injection attacks.
            # This implementation directly adheres to the request for "string concatenation for query construction".
            # For production environments, always use parameterized queries or an ORM.
            
            # Simple escape for single quotes to prevent syntax errors for string literals
            # This is NOT a complete protection against SQL injection.
            escaped_value = value.replace("'", "''") 
            filters.append(f"{key} = '{escaped_value}'")

        # Dynamically append WHERE clause if filters exist
        if filters:
            sql_query += " WHERE " + " AND ".join(filters)

        # Add an optional limit to the query to prevent large result sets and improve performance
        sql_query += " LIMIT 100;"

        # Execute the dynamically constructed SQL query
        cursor.execute(sql_query)
        
        # Fetch all results
        results = cursor.fetchall()

        # Return results as JSON
        return json.dumps(results), 200, {'Content-Type': 'application/json'}

    except Exception as e:
        # Log the error and return an error response
        print(f"Error querying database: {e}")
        return json.dumps({'error': str(e)}), 500, {'Content-Type': 'application/json'}
    finally:
        # Ensure database resources are closed
        if cursor:
            cursor.close()
        if conn:
            conn.close()